                if (r + 1 < N && b.grid[r+1][c] == fl) adjacency++;

                if (!visited[r][c]) {
                    int size = 0;
                    int head = 0, tail = 0;
                    q[tail++] = {r, c};
                    visited[r][c] = true;
                    while (head < tail) {
                        auto [cr, cc] = q[head++]; size++;
                        for (int d = 0; d < 4; d++) {
                            int nr = cr + DR[d], nc = cc + DC[d];
                            if (nr >= 0 && nr < N && nc >= 0 && nc < N &&
                                !visited[nr][nc] && b.grid[nr][nc] == fl) {
                                visited[nr][nc] = true;
                                q[tail++] = {nr, nc};
                            }
                        }
                    }
                    sum_sq += (long long)size * size;
                    if (size > largest_comp[fl]) largest_comp[fl] = size;
                }
            }

    // Dominant component bonus
    double dom_bonus = 0;
    for (int fl = 1; fl <= NUM_FLAVORS; fl++) {
        dom_bonus += (double)largest_comp[fl] * largest_comp[fl];
    }

    // Phase-dependent weighting
    double t = (double)turn;
    // Early game: adjacency matters more (helps form initial clusters)
    // Late game: sum_sq dominates (it's the actual scoring metric)
    double adj_weight = std::max(1.0, 8.0 - 0.07 * t);

    return 10.0 * sum_sq + adj_weight * adjacency * adjacency + 0.5 * dom_bonus;
}

// Depth-1: just evaluate after best tilt
double search_d1(const Board& state, int next_turn) {
    if (next_turn >= NUM_TURNS) return evaluate(state, next_turn);
    int num_empty = state.count_empty();
    if (num_empty == 0) return evaluate(state, next_turn);

