            tilted.tilt(d);
            double val = evaluate(tilted, next_turn + 1);
            if (val > best_val) best_val = val;
        }
        total += best_val;
    }
    return total / ns;
}

// Depth-2: sample + best direction + depth-1
double search_d2(const Board& state, int next_turn, int samples_d2, int samples_d1) {
