            }
            double val = t2 / ns2;
            if (val > best_val) best_val = val;
        }
        total += best_val;
    }
    return total / ns;
}

// Depth-3: sample + best direction + depth-2
double search_d3(const Board& state, int next_turn, int s3, int s2, int s1) {
