                if (grid[r][c] == 0)
                    if (++count == p) return {r, c};
        return {-1, -1};
    }

    int count_empty() const { return N * N - num_candies; }

    void tilt(int dir) {
        if (dir == 0) {
            for (int c = 0; c < N; c++) {
                int wr = 0;
                for (int r = 0; r < N; r++)
                    if (grid[r][c]) {
                        if (r != wr) { grid[wr][c] = grid[r][c]; grid[r][c] = 0; }
                        wr++;
