// Key idea: use much higher samples in early game (where board is sparse = eval is cheap)
// and more aggressive time management
int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    for (int i = 0; i < NUM_TURNS; i++) std::cin >> flavors[i];

    memset(flavor_counts, 0, sizeof(flavor_counts));
    for (int i = 0; i < NUM_TURNS; i++) flavor_counts[flavors[i]]++;

    assign_targets();

    global_rng = XorshiftRNG(std::chrono::steady_clock::now().time_since_epoch().count());

    Board current_board;
    current_board.clear();

    auto global_start = std::chrono::steady_clock::now();

    for (int t = 0; t < NUM_TURNS; t++) {
        int p;
        std::cin >> p;
        auto [r, c] = current_board.find_pth_empty(p);
        current_board.place(r, c, flavors[t]);

        auto now = std::chrono::steady_clock::now();
        int elapsed_ms = (int)std::chrono::duration_cast<std::chrono::milliseconds>(
            now - global_start).count();
        int remaining_ms = 1900 - elapsed_ms;
        int turns_left = NUM_TURNS - t;

        // Non-uniform time allocation: early turns get more budget
        // Early turns are faster (sparse board) so we can afford more samples
        // Weight: 1.5x for first 30 turns, 1.0x for middle, 0.7x for last 30
        double weight;
        if (t < 30) weight = 1.5;
        else if (t < 70) weight = 1.0;
        else weight = 0.7;

        double total_weight = 0;
        for (int i = t; i < NUM_TURNS; i++) {
            if (i < 30) total_weight += 1.5;
            else if (i < 70) total_weight += 1.0;
            else total_weight += 0.7;
        }
        double budget = remaining_ms * weight / total_weight;

        int s_d2, s_d1;
        if (budget > 35) { s_d2 = 28; s_d1 = 11; }
        else if (budget > 25) { s_d2 = 23; s_d1 = 9; }
        else if (budget > 18) { s_d2 = 21; s_d1 = 8; }
        else if (budget > 12) { s_d2 = 18; s_d1 = 7; }
        else if (budget > 6) { s_d2 = 14; s_d1 = 5; }
        else { s_d2 = 8; s_d1 = 3; }

        int best_dir = 0;
        double best_val = -1e18;

        for (int d = 0; d < 4; d++) {
            Board tilted = current_board;
            tilted.tilt(d);

            // Depth-2 expectimax
            int num_empty = tilted.count_empty();
            if (t + 1 >= NUM_TURNS || num_empty == 0) {
                double val = evaluate(tilted, t + 1);
                if (val > best_val) { best_val = val; best_dir = d; }
                continue;
            }

            int next_flavor = flavors[t + 1];
            int ns = std::min(s_d2, num_empty);

            double total = 0.0;
            for (int s = 0; s < ns; s++) {
                int pi = (ns >= num_empty) ? s + 1 : global_rng.uniform(1, num_empty);
                Board placed = tilted;
                auto [ri, ci] = placed.find_pth_empty(pi);
                placed.place(ri, ci, next_flavor);

                double best_inner = -1e18;
                for (int d2 = 0; d2 < 4; d2++) {
                    Board tilted2 = placed;
                    tilted2.tilt(d2);

                    // Inner depth-1
                    int ne2 = tilted2.count_empty();
                    if (t + 2 >= NUM_TURNS || ne2 == 0) {
                        double val = evaluate(tilted2, t + 2);
                        if (val > best_inner) best_inner = val;
                        continue;
                    }
                    int nf2 = flavors[t + 2];
                    int ns2 = std::min(s_d1, ne2);
                    double t2_sum = 0.0;
                    for (int s2 = 0; s2 < ns2; s2++) {
                        int p2 = (ns2 >= ne2) ? s2 + 1 : global_rng.uniform(1, ne2);
                        Board placed2 = tilted2;
                        auto [r2, c2] = placed2.find_pth_empty(p2);
                        placed2.place(r2, c2, nf2);
                        double best2 = -1e18;
                        for (int d3 = 0; d3 < 4; d3++) {
                            Board tilted3 = placed2;
                            tilted3.tilt(d3);
                            double v = evaluate(tilted3, t + 3);
                            if (v > best2) best2 = v;
                        }
                        t2_sum += best2;
                    }
                    double val = t2_sum / ns2;
                    if (val > best_inner) best_inner = val;
                }
                total += best_inner;
            }
            double val = total / ns;
            if (val > best_val) { best_val = val; best_dir = d; }
        }

        std::cout << DIR_CHARS[best_dir] << std::endl;
        current_board.tilt(best_dir);
    }

    return 0;
}
